import csv
import time

x =  int("A111F275CC2E7588000001D300A31E76336D15B9D314CD1A1D8F3D3556975EED", 16)
N = int("", 16)

def measure(T):
    start = time.perf_counter_ns()
    pow(x, 2**T, N)
    elapsed_ns = time.perf_counter_ns() - start
    return int(elapsed_ns / 1000000)


with open("evaluation/data/impl_solve_vm.csv", "a", newline="") as f:
    writer = csv.writer(f)
    for t in range(5,25):
        print("Iteration ", t)
        ms = measure(2**t)
        writer.writerow(["python",(2**t), ms])